from flask import Flask, request, jsonify
from functools import wraps
import hashlib
import secrets
import time

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# In-memory storage for users and tokens (use database in production)
users = {
    "admin": hashlib.sha256("password".encode()).hexdigest()
}
tokens = {}

def generate_token(username):
    token = secrets.token_urlsafe(32)
    tokens[token] = {
        "username": username,
        "timestamp": time.time()
    }
    return token

def verify_token(token):
    if token not in tokens:
        return False
    if time.time() - tokens[token]["timestamp"] > 3600:  # 1 hour expiry
        del tokens[token]
        return False
    return True

def get_username_from_token(token):
    return tokens.get(token, {}).get("username")

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token or not verify_token(token):
            return jsonify({"message": "Invalid or missing token"}), 401
        return f(*args, **kwargs)
    return decorated

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({"message": "Username and password required"}), 400
    
    hashed_password = hashlib.sha256(password.encode()).hexdigest()
    
    if username in users and users[username] == hashed_password:
        token = generate_token(username)
        return jsonify({"token": token}), 200
    
    return jsonify({"message": "Invalid credentials"}), 401

@app.route('/protected', methods=['GET'])
@token_required
def protected():
    return jsonify({"message": "This is a protected endpoint"}), 200

@app.route('/public', methods=['GET'])
def public():
    return jsonify({"message": "This is a public endpoint"}), 200

if __name__ == '__main__':
    app.run(debug=True)